@@ -1,13 +1,422 @@
+@import url("https://fonts.googleapis.com/css2?family=IBM+Plex+Sans:wght@400;500;600&family=Space+Grotesk:wght@500;600;700&display=swap");
+
 :root {
   color-scheme: light;
+  --font-display: "Space Grotesk", "Inter", system-ui, sans-serif;
+  --font-body: "IBM Plex Sans", "Inter", system-ui, sans-serif;
+  --bg: #f4efe8;
+  --bg-glow: #fce6c6;
+  --surface: #ffffff;
+  --surface-muted: #f5f2ed;
+  --ink: #1f2329;
+  --ink-muted: #6b6a67;
+  --accent: #2c6f6d;
+  --accent-strong: #1b4d4c;
+  --danger: #c44d41;
+  --warning: #c1882d;
+  --positive: #2a7f62;
+  --shadow: 0 14px 40px rgba(31, 35, 41, 0.08);
+  --border: rgba(31, 35, 41, 0.12);
+}
+
+[data-theme="dusk"] {
+  color-scheme: dark;
+  --bg: #171615;
+  --bg-glow: #45392e;
+  --surface: #1f1d1b;
+  --surface-muted: #262321;
+  --ink: #f5f0ea;
+  --ink-muted: #b1aba3;
+  --accent: #ffb24a;
+  --accent-strong: #d5902e;
+  --danger: #e07a6b;
+  --warning: #f3c067;
+  --positive: #76c19a;
+  --border: rgba(245, 240, 234, 0.12);
+}
+
+* {
+  box-sizing: border-box;
 }

 body {
   margin: 0;
-  background: #f8fafc;
-  color: #0f172a;
+  font-family: var(--font-body);
+  background: radial-gradient(circle at top left, var(--bg-glow), var(--bg) 45%);
+  color: var(--ink);
+  min-height: 100vh;
 }

 #root {
   min-height: 100vh;
 }
+
+h1,
+h2,
+h3,
+h4 {
+  font-family: var(--font-display);
+  margin: 0;
+}
+
+p {
+  line-height: 1.6;
+}
+
+button,
+input {
+  font-family: inherit;
+}
+
+.app-shell {
+  display: flex;
+  min-height: 100vh;
+}
+
+.sidebar {
+  width: 260px;
+  background: var(--surface);
+  border-right: 1px solid var(--border);
+  display: flex;
+  flex-direction: column;
+  padding: 24px 20px;
+  gap: 24px;
+  box-shadow: var(--shadow);
+}
+
+.sidebar__brand {
+  display: flex;
+  align-items: center;
+  gap: 12px;
+}
+
+.brand-mark {
+  width: 40px;
+  height: 40px;
+  background: var(--accent);
+  color: #fffaf2;
+  display: grid;
+  place-items: center;
+  border-radius: 14px;
+}
+
+.brand-title {
+  font-weight: 600;
+}
+
+.brand-subtitle {
+  font-size: 0.85rem;
+  color: var(--ink-muted);
+}
+
+.sidebar__nav {
+  display: grid;
+  gap: 6px;
+}
+
+.nav-link {
+  display: flex;
+  align-items: center;
+  gap: 12px;
+  padding: 10px 12px;
+  border-radius: 12px;
+  color: inherit;
+  text-decoration: none;
+  background: transparent;
+  transition: background 0.2s ease, color 0.2s ease;
+}
+
+.nav-link--active {
+  background: var(--surface-muted);
+  color: var(--accent-strong);
+}
+
+.nav-badge {
+  margin-left: auto;
+  background: var(--accent);
+  color: #fffaf2;
+  border-radius: 999px;
+  font-size: 0.75rem;
+  padding: 2px 8px;
+}
+
+.sidebar__footer {
+  margin-top: auto;
+}
+
+.sidebar__hint {
+  display: flex;
+  align-items: center;
+  gap: 8px;
+  font-size: 0.85rem;
+  color: var(--ink-muted);
+}
+
+.sidebar__hint kbd {
+  background: var(--surface-muted);
+  border-radius: 6px;
+  padding: 2px 6px;
+  font-size: 0.75rem;
+}
+
+.app-main {
+  flex: 1;
+  display: flex;
+  flex-direction: column;
+}
+
+.topbar {
+  display: flex;
+  justify-content: space-between;
+  align-items: center;
+  padding: 28px 32px 16px;
+}
+
+.topbar h1 {
+  font-size: 1.75rem;
+}
+
+.topbar__actions {
+  display: flex;
+  align-items: center;
+  gap: 12px;
+}
+
+.icon-button {
+  border: 1px solid var(--border);
+  background: var(--surface);
+  border-radius: 999px;
+  padding: 6px 14px;
+  display: inline-flex;
+  align-items: center;
+  gap: 8px;
+  cursor: pointer;
+}
+
+.primary-button {
+  border: none;
+  background: var(--accent);
+  color: #fffaf2;
+  border-radius: 12px;
+  padding: 10px 16px;
+  cursor: pointer;
+  display: inline-flex;
+  gap: 8px;
+  align-items: center;
+  text-decoration: none;
+}
+
+.app-content {
+  padding: 0 32px 40px;
+  flex: 1;
+}
+
+.page {
+  display: grid;
+  gap: 24px;
+}
+
+.grid {
+  display: grid;
+  gap: 20px;
+}
+
+.grid--2 {
+  grid-template-columns: repeat(2, minmax(0, 1fr));
+}
+
+.grid--3 {
+  grid-template-columns: repeat(3, minmax(0, 1fr));
+}
+
+.card {
+  background: var(--surface);
+  border: 1px solid var(--border);
+  border-radius: 18px;
+  padding: 20px;
+  box-shadow: var(--shadow);
+}
+
+.card--wide {
+  grid-column: 1 / -1;
+}
+
+.card--compact h4 {
+  font-family: var(--font-display);
+  font-size: 1.4rem;
+}
+
+.card__header {
+  display: flex;
+  justify-content: space-between;
+  align-items: center;
+  margin-bottom: 14px;
+}
+
+.metric {
+  font-size: 2.4rem;
+  font-family: var(--font-display);
+}
+
+.muted {
+  color: var(--ink-muted);
+  margin: 6px 0 0;
+}
+
+.eyebrow {
+  font-size: 0.75rem;
+  text-transform: uppercase;
+  letter-spacing: 0.12em;
+  color: var(--ink-muted);
+  margin-bottom: 8px;
+}
+
+.table {
+  display: grid;
+  gap: 10px;
+}
+
+.table__row {
+  display: grid;
+  grid-template-columns: repeat(4, minmax(0, 1fr));
+  align-items: center;
+  gap: 12px;
+}
+
+.table__row--header {
+  font-size: 0.75rem;
+  text-transform: uppercase;
+  letter-spacing: 0.1em;
+  color: var(--ink-muted);
+}
+
+.status-pill {
+  display: inline-flex;
+  align-items: center;
+  gap: 6px;
+  border-radius: 999px;
+  padding: 4px 10px;
+  font-size: 0.75rem;
+  border: 1px solid transparent;
+}
+
+.status-pill--muted {
+  background: var(--surface-muted);
+  color: var(--ink-muted);
+}
+
+.status-pill--positive {
+  background: rgba(42, 127, 98, 0.15);
+  color: var(--positive);
+}
+
+.status-pill--warning {
+  background: rgba(193, 136, 45, 0.15);
+  color: var(--warning);
+}
+
+.status-pill--danger {
+  background: rgba(196, 77, 65, 0.15);
+  color: var(--danger);
+}
+
+.mono {
+  font-family: "IBM Plex Mono", "JetBrains Mono", ui-monospace, monospace;
+  font-size: 0.85rem;
+}
+
+.palette-backdrop {
+  position: fixed;
+  inset: 0;
+  background: rgba(15, 14, 13, 0.45);
+  display: grid;
+  place-items: center;
+  z-index: 50;
+}
+
+.palette {
+  width: min(620px, 90vw);
+  background: var(--surface);
+  border-radius: 18px;
+  border: 1px solid var(--border);
+  box-shadow: var(--shadow);
+  overflow: hidden;
+}
+
+.palette__input {
+  display: flex;
+  align-items: center;
+  gap: 10px;
+  padding: 16px;
+  border-bottom: 1px solid var(--border);
+}
+
+.palette__input input {
+  border: none;
+  outline: none;
+  background: transparent;
+  flex: 1;
+  font-size: 1rem;
+}
+
+.palette__input kbd {
+  background: var(--surface-muted);
+  border-radius: 6px;
+  padding: 2px 6px;
+  font-size: 0.7rem;
+}
+
+.palette__list {
+  padding: 10px;
+  display: grid;
+  gap: 6px;
+}
+
+.palette__item {
+  border: none;
+  background: transparent;
+  text-align: left;
+  padding: 10px 12px;
+  border-radius: 12px;
+  cursor: pointer;
+  display: flex;
+  justify-content: space-between;
+  align-items: center;
+}
+
+.palette__item:hover {
+  background: var(--surface-muted);
+}
+
+.palette__empty {
+  padding: 20px;
+  color: var(--ink-muted);
+}
+
+@media (max-width: 960px) {
+  .sidebar {
+    width: 210px;
+  }
+  .grid--3 {
+    grid-template-columns: 1fr;
+  }
+  .grid--2 {
+    grid-template-columns: 1fr;
+  }
+}
+
+@media (max-width: 720px) {
+  .sidebar {
+    display: none;
+  }
+  .topbar {
+    padding: 20px;
+  }
+  .app-content {
+    padding: 0 20px 32px;
+  }
+  .table__row {
+    grid-template-columns: 1fr;
+    gap: 6px;
+  }
+}
